# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

from fastapi import FastAPI
from pydantic import BaseModel, Field
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import Pipeline
import numpy as np

app = FastAPI(title="Spam Detection API", version="1.0.0")

TRAINING_DATA = [
    ("Congratulations, you have won a free prize! Click now to claim.", 1),
    ("Urgent: your account has been selected for a cash reward.", 1),
    ("Limited time offer! Buy now and get 50% off.", 1),
    ("You have been chosen for a free gift card.", 1),
    ("Claim your bonus immediately by visiting this link.", 1),
    ("Winner! You've received a special promotion.", 1),
    ("This is not spam, just a regular business meeting update.", 0),
    ("Please find the attached report for review.", 0),
    ("Can we reschedule our call to tomorrow afternoon?", 0),
    ("Here are the notes from today's project discussion.", 0),
    ("Thank you for your email. I will respond shortly.", 0),
    ("Let's confirm the agenda for next week's meeting.", 0),
    ("Your invoice has been processed and is attached.", 0),
    ("Reminder: the team standup starts at 9 AM.", 0),
]

model = Pipeline(
    steps=[
        ("vectorizer", CountVectorizer(stop_words="english", ngram_range=(1, 2), min_df=1)),
        ("clf", LogisticRegression(max_iter=1000, random_state=42)),
    ]
)

X_train = [text for text, label in TRAINING_DATA]
y_train = [label for text, label in TRAINING_DATA]
model.fit(X_train, y_train)


class EmailRequest(BaseModel):
    text: str = Field(..., min_length=1, description="Email text to evaluate")


class SpamResponse(BaseModel):
    spam_probability: float
    is_spam: bool


@app.get("/health")
def health():
    return {"status": "ok"}


@app.post("/predict", response_model=SpamResponse)
def predict_spam(req: EmailRequest):
    proba = model.predict_proba([req.text])[0]
    spam_probability = float(proba[1])
    return SpamResponse(spam_probability=spam_probability, is_spam=spam_probability >= 0.5)